from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

client = MongoClient('mongodb://localhost:27017/')
db = client.cms
users_collection = db.users

@app.route('/user', methods=['POST'])
def create_user():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400
    hashed_password = generate_password_hash(password)
    user_id = users_collection.insert_one({
        'username': username,
        'password': hashed_password
    }).inserted_id
    return jsonify({'user_id': str(user_id)}), 201

@app.route('/user/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users_collection.find_one({'_id': ObjectId(user_id)})
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'username': user['username']}), 200

@app.route('/users', methods=['GET'])
def list_users():
    users = users_collection.find()
    user_list = [{'user_id': str(user['_id']), 'username': user['username']} for user in users]
    return jsonify(user_list), 200

@app.route('/user/<user_id>', methods=['PUT'])
def update_user(user_id):
    data = request.json
    new_data = {}
    if 'username' in data:
        new_data['username'] = data['username']
    if 'password' in data:
        new_data['password'] = generate_password_hash(data['password'])
    if not new_data:
        return jsonify({'error': 'No data to update'}), 400
    result = users_collection.update_one({'_id': ObjectId(user_id)}, {'$set': new_data})
    if result.matched_count == 0:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'message': 'User updated'}), 200

@app.route('/user/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    result = users_collection.delete_one({'_id': ObjectId(user_id)})
    if result.deleted_count == 0:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'message': 'User deleted'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_users():
    pipeline = [
        {'$group': {'_id': '$username', 'count': {'$sum': 1}}},
        {'$sort': {'count': -1}}
    ]
    result = list(users_collection.aggregate(pipeline))
    return jsonify(result), 200

if __name__ == '__main__':
    app.run(debug=True)